-- Enrichment marathon batch: Clearbit, Clementine, Clever, CleverTap, Clicky, Climate Corporation, ClipGrab, Clockwork Micro

-- ── Clearbit ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Clearbit was a B2B data enrichment and company/contact intelligence platform founded in 2014 in San Francisco. HubSpot acquired Clearbit in December 2023 and has since folded its enrichment technology into HubSpot as Breeze Intelligence, part of the broader Breeze AI suite. As of 2026 the standalone Clearbit product is retired for new customers, with enrichment, buyer intent, and form-shortening features sold only as a HubSpot add-on.$q$, short_description),
  pricing_model = COALESCE($q$Credit-based add-on bundled with a required paid HubSpot subscription (no longer sold as a standalone product)$q$, pricing_model),
  starting_price = COALESCE($q$Approximately 75 USD per month total (about 30 USD per month for HubSpot Starter plus about 45 USD per month for 100 Breeze Intelligence credits on annual billing)$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$Now part of HubSpot (which has over 7000 employees); the original Clearbit team was under 200 people prior to the 2023 acquisition$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States (original headquarters; now operated as part of HubSpot, headquartered in Cambridge, Massachusetts)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Clearbit (Breeze Intelligence): Pricing and Features 2026$q$, seo_title),
  seo_meta_description = COALESCE($q$Clearbit is now Breeze Intelligence under HubSpot. See 2026 pricing, features, pros and cons of this B2B data enrichment and intent platform.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Clearbit is a B2B data enrichment and company/contact intelligence platform originally founded in 2014 in San Francisco, California by Alex MacCaw, Harlow Ward, and Rob Holland. For nearly a decade it operated as an independent company, raising seed and Series A venture funding and becoming a widely used integration inside sales and marketing stacks built on Salesforce, HubSpot, Marketo, and Segment. Clearbit's core technology enriched partial records, such as an email address or a company domain, into full firmographic and technographic profiles: employee count, industry, estimated revenue, funding history, technology stack, job title, and seniority. In December 2023, HubSpot announced the acquisition of Clearbit, and throughout 2024 the standalone Clearbit product was progressively folded into HubSpot's Breeze AI suite under the new name Breeze Intelligence. As of 2026, Clearbit no longer exists as an independently purchasable SaaS product; new customers cannot sign up for clearbit.com directly, and the technology is sold exclusively as a credit-based add-on that requires an active paid HubSpot subscription (Starter, Professional, or Enterprise) as a prerequisite. Breeze Intelligence's core capabilities carried over from Clearbit include automatic enrichment of HubSpot CRM company and contact records, buyer intent signals that flag accounts showing increased research or engagement activity, form shortening that pre-fills known contact fields to reduce friction on HubSpot forms, and company-level visitor identification (often called Reveal) that deanonymizes anonymous website traffic down to the company level. Pricing operates on a monthly credit pool: entry-level packages of around 100 credits cost roughly 45 to 50 USD per month depending on annual versus monthly billing, mid-tier packages of 1000 credits run around 150 USD per month, and larger 10000-credit packages run around 700 USD per month; these costs are on top of the mandatory HubSpot subscription, which starts around 30 USD per month for Starter. Combined, minimum realistic total spend for a small team lands around 75 USD per month, while mid-market teams on HubSpot Professional commonly spend 1000 to 5000 USD or more per month once they add sufficient enrichment volume. Credits expire monthly with no rollover, which is a common source of billing confusion for teams evaluating total cost of ownership post-acquisition. The most significant practical implication for buyers researching Clearbit in 2026 is that it is functionally no longer available to teams outside the HubSpot ecosystem; organizations using Salesforce alone, Pipedrive, or other CRMs without a parallel HubSpot subscription cannot access the current version of the technology, and commonly evaluate alternatives such as ZoomInfo, Apollo.io, Cognism, or Clay instead. For HubSpot-native teams, however, Breeze Intelligence represents a natural extension of the platform they already use daily, with the enrichment, intent, and identification features appearing directly inside familiar HubSpot workflows, lead-scoring rules, and form builders rather than requiring a separate tool and a separate login. Anyone searching for Clearbit pricing, the Clearbit API, or Clearbit alternatives in 2026 should understand this rebrand and bundling change as the central fact governing how the product can now be bought and used.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd4223752-ad10-4cc5-a3d4-de58751958ab';

