-- ── Clockwork Micro ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Clockwork Micro is a Seattle-based geospatial technology company, founded in 2021 by Brendan Farrell, that provides web-mapping and cartography APIs rather than semiconductor hardware. Its product line includes an Elevation API, Basemap and Terrain Tile services, USGS Topo Maps, Map Maker (a low-code map-building tool), and DB2Vector (SQL-to-vector-tile conversion), aimed at developers who need to embed custom maps without building cartography infrastructure from scratch.$q$, short_description),
  pricing_model = COALESCE($q$Tiered, usage-based API pricing with a free tier and metered overage$q$, pricing_model),
  starting_price = COALESCE($q$Free tier available (50000 API and tile requests per service); paid plans start at 25 USD per month$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$Small startup, fewer than 20 employees (exact headcount not publicly disclosed)$q$, company_size),
  headquarters = COALESCE($q$Seattle, Washington, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Clockwork Micro: Mapping API Pricing and Features 2026$q$, seo_title),
  seo_meta_description = COALESCE($q$Clockwork Micro offers elevation, basemap, and terrain mapping APIs for developers. See 2026 pricing, features, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Clockwork Micro is a geospatial technology company, not a semiconductor or wireless-chip manufacturer despite what its name might suggest to some searchers. Founded in 2021 by Brendan Farrell and based in Seattle, Washington, the company builds web-mapping and cartography application programming interfaces (APIs) aimed at software developers and organizations who need to embed custom, styled maps into products without building and operating their own map-tile infrastructure from scratch. Its stated mission is to abstract away the time-consuming technical work involved in serving a map built on custom data, letting developers focus on how they want their map to look and what it should present rather than on the underlying tile-serving, projection, and rendering pipeline. Clockwork Micro's product line spans several distinct but related tools. Its Elevation API returns terrain elevation data for a given location or region, useful for applications like hiking route planning or terrain visualization. Its Basemap and Terrain Tile services provide foundational and terrain-focused map tile layers that developers can style and build on top of. It also serves USGS Topo Maps, including official United States Geological Survey 7.5-minute topographic quadrangle tiles, which are widely used in outdoor recreation, land-use, and government mapping applications. For less technical users, Map Maker offers a low-code interface for building interactive, modular maps directly from custom data, while a companion Simple Styler tool provides a visual interface for adjusting map layer colors, opacity, and boundary appearance without writing styling code by hand. A more developer-oriented tool, DB2Vector, converts the results of SQL queries directly into vector tile endpoints, letting teams that already store geospatial data in a relational database expose it as map tiles without standing up a separate tile-generation pipeline. Clockwork Micro's pricing follows a tiered, usage-based API model with four levels: a free Personal tier including 50000 API and tile requests per service; a Standard tier at 25 USD per month raising that to 100000 requests per service; a Commercial tier at 195 USD per month including 1000000 requests per service at a reduced overage rate of 6 cents per 1000 additional requests, compared to 8 cents per 1000 on the lower tiers; and a custom Enterprise tier for organizations with larger or contractually negotiated needs. Because Clockwork Micro is a small and relatively young company compared to established mapping platforms such as Mapbox, Esri, or Google Maps Platform, prospective customers evaluating it for production or mission-critical use should independently verify current API uptime, long-term roadmap commitments, and company stability directly with Clockwork Micro rather than assuming the maturity of a larger incumbent provider.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3bd680fb-ffaf-4404-9c06-bac18a4eedf9';

